Connecting Database 
"connect.cpp" shows how to connect database.The file must contain
            the head file "client.hpp" and use namespace
            "sdbclient".#include <stdio.h>
#include <iostream>
#include "client.hpp"

using namespace std ;
using namespace sdbclient ;

// Display Syntax Error
void displaySyntax ( CHAR *pCommand ) ;

INT32 main ( INT32 argc, CHAR **argv )
{
   // define a sdb object
   // use to connect to database
   sdb connection ;
   INT32 rc = SDB_OK ;

   // verify syntax
   if ( 5 != argc )
   {
      displaySyntax ( (CHAR*)argv[0] ) ;
      exit ( 0 ) ;
   }

   // read argument
   CHAR *pHostName    = (CHAR*)argv[1] ;
   UINT16 Port        =  atoi(argv[2]) ;
   CHAR *pUsr         = (CHAR*)argv[3] ;
   CHAR *pPasswd      = (CHAR*)argv[4] ;

   // connect to database
   rc = connection.connect ( pHostName, Port, pUsr, pPasswd ) ;
   if( rc!=SDB_OK )
   {
      cout<<"Fail to connet to database, rc = "<<rc<<endl ;
      goto error ;
   }
   else
      cout<<"connect success!"<<endl ;
done:
   // disconnect from database
   connection.disconnect () ;
   return 0 ;
error:
   goto done ;
}

// Display Syntax Error
void displaySyntax ( CHAR *pCommand )
{
   cout<<"Syntax:"<<pCommand<<" <host><name><servicename>\
 <username><password>"<<endl ;
 }
In
            Linux, you can compile and link the dynamic library "libsdbcpp.so" like this:
            $ gcc -o connect connect.cpp -I <PATH>/sequoiadb/client/CPP/include -lsdbcpp -L <PATH>/sequoiadb/client/CPP/lib
Execution results:
$ ./connect localhost 11810 "" ""
connect success!
In
            Windows,compiling and linking the dynamic library "sdbcpp.lib" and "sdbcpp.dll" like
            this:> cl /Fo connect.obj /c connect.cpp /I <PATH>\sequoiadb\client\CPP\include /wd4047
> link /OUT:connect.exe /LIBPATH:<PATH>\sequoiadb\client\CPP \lib sdbcpp.lib connect.obj 
> copy <PATH>\sequoiadb\client\CPP\lib\sdbcpp.dll .
Execution results:
> connect.exe localhost 11810 "" ""
> connect success!

This sample connects to the port "11810" of local database, usename and password are
              null, users can configure params according to needs. For example, when the user have
              created usename and password, you must use the correct usename and password to connect
              the database.

Inserting
            Data// Firstly , a BSON object is created
bson obj;
bson_init( &obj ) ;
bson_append_string( &obj, “name”, “tom” ) ;
bson_append_int( &obj, “age”, 24 ) ;
bson_finish( &obj ) ;
// Then,insert it into a collection
collection.insert ( &obj ) ;
bson_destroy( &obj ) ;
obj
            is inputed param and inserted data.

Query
            // Define a cursor object
   sdbCursor cursor ;
   …
   // Search for all records and put the results in the cursor object
   collection.query ( cursor, NULL, NULL, NULL, NULL, 0, -1 ) ;
   // Show every record in cursor
   bson_init(&obj);
   while( !( rc=cursor.next( obj ) ) )
   {
      bson_print( &obj ) ;
      bson_destroy(&obj) ;
      bson_init(&obj);
   }
   bson_destroy(&obj) ;

            In a query, a cursor object is used to store the result set of a query . You can get
            results by manipulating the cursor.  This sample uses the next interface of
            cursor manipulation to get one record in the result set. This sample does not set
            querying conditions,filtering conditions and ordering,only use default index.

Index
               #define INDEX_NAME "index"
   …
   // Firstly we create a bson that contains the information of the index.
   bson_init( &obj ) ;
   bson_append_int( &obj, "name", 1 ) ;
   bson_append_int( &obj, "age", -1 ) ;
   bson_finish( &obj ) ;
   // Create an index with the BOSN object.
   collection.createIndex ( &obj, INDEX_NAME, FALSE, FALSE ) ;
   bson_destroy ( &obj ) ;   


            Here, we create an index in the collection specified by the collection object
              collection . It is in ascending order on "name" and descending order on "age"

Update
               // Create a BSON object that contains updating rules
   bson_init( &rule ) ;
   bson_append_start_object ( &rule, "$set" ) ;
   bson_append_int ( &rule, "age", 19 ) ;
   bson_append_finish_object ( &rule ) ;
   bson_finish ( &rule ) ;
   //  Print updating rule.
   bson_print( &rule ) ;
   // Update records.
   collection.update( &rule, NULL, NULL ) ;
   bson_destroy(&rule);
Here,as
            no record matching conditions have specified,then this example will update all records
            in the collection which collection handle specified.

 ReplicaSet Operations 
ReplicaSet Operations contains creating
            ReplicaSets(sdbCreateShard)、getting ReplicaSet handles(sdbGetShard)、starting
            ReplicaSet(sdbStartShard) and stopping ReplicaSet(sdbStopShard). The following shows the
            ReplicaSet Operations, and real application should include error detecting, etc.
             // define a ReplicaSet Instance
   sdbShard shard  ;
   // define a null map object,it means that no more configuration information when create data nodes
   map<string,string> config ;
   …
   // create a catalog ReplicaSet at first
   connection.createCataShard ( HOST_NAME, SERVICE_NAME,
                          CATALOG_SHARD_PATH , NULL ) ;
   // sleep 5s to wait starting catalog ReplicaSet and electing master and slave.
   sleep( 5 ) ;
   // create data ReplicaSet
   connection.createShard ( REPLICA_SHARD_NAME, shard ) ;

   // create data nodes
   shard.createNode ( HOST_NAME1, SERVICE_NAME1, DATABASE_PATH1, config ) ;
   …
   // start ReplicaSet
   shard.start () ;

Data Node Operations 
Data Node Operations contains create data
            node(sdbShardcreateNode)、get master data node(sdbShardgetMaster)、get slave data
            node(sdbShardGetSlave)、start data node (sdbNodeStop) and stop data
            node(sdbNodeStop),etc. The following shows the Data Node Operations, and real
            application should include error detecting, etc.
             // define a data node instance
   sdbNode masternode ;
   sdbNode slavenode ;
   …
   // sleep 15s to wait starting data ReplicaSet and electing master and slave
   sleep( 15 ) ;

   // get master data node
   shard.getMaster( masternode ) ;
   //get slave data node
   shard.getSlave( slavenode ) ;
